import React, { useState, useEffect, useCallback } from "react";
import { ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

import Sidebar from "./components/Sidebar";
import Topbar from "./components/Topbar";
import Dashboard from "./pages/Dashboard";
import NeedsPage from "./pages/NeedsPage";
import VolunteersPage from "./pages/VolunteersPage";
import MapPage from "./pages/MapPage";
import MatchingPage from "./pages/MatchingPage";
import SubmitNeed from "./pages/SubmitNeed";
import AddVolunteer from "./pages/AddVolunteer";
import LoadingSpinner from "./components/LoadingSpinner";

import { fetchPrioritizedNeeds, fetchVolunteers, fetchAssignments, seedDatabase } from "./utils/api";
import { toast } from "react-toastify";

const PAGE_TITLES = {
  dashboard: "Dashboard",
  needs: "Community Needs",
  volunteers: "Volunteers",
  map: "Map View",
  matching: "Smart Match",
  "submit-need": "Submit Need",
  "add-volunteer": "Add Volunteer",
};

export default function App() {
  const [page, setPage] = useState("dashboard");
  const [needs, setNeeds] = useState([]);
  const [volunteers, setVolunteers] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);

  const loadAll = useCallback(async () => {
    try {
      const [n, v, a] = await Promise.all([
        fetchPrioritizedNeeds(),
        fetchVolunteers(),
        fetchAssignments(),
      ]);
      setNeeds(n.data.data || []);
      setVolunteers(v.data.data || []);
      setAssignments(a.data.data || []);
    } catch (e) {
      console.error("Failed to load data", e);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { loadAll(); }, [loadAll]);

  const handleSeed = async () => {
    if (!window.confirm("This will add sample needs and volunteers to Firestore. Continue?")) return;
    try {
      setSeeding(true);
      await seedDatabase();
      toast.success("Sample data seeded successfully!");
      await loadAll();
    } catch {
      toast.error("Seeding failed. Ensure backend is running and Firestore is configured.");
    } finally {
      setSeeding(false);
    }
  };

  const urgentCount = needs.filter((n) => n.urgency === "high" && n.status !== "completed").length;
  const availableCount = volunteers.filter((v) => v.availability).length;

  if (loading) return <div style={{ display: "flex", justifyContent: "center", alignItems: "center", height: "100vh" }}><LoadingSpinner message="Connecting to ReliefLink..." /></div>;

  return (
    <div className="app">
      <ToastContainer position="top-right" autoClose={3000} hideProgressBar={false} />
      <Sidebar page={page} setPage={setPage} urgentCount={urgentCount} availableCount={availableCount} />
      <div className="main">
        <Topbar
          title={PAGE_TITLES[page]}
          urgentCount={urgentCount}
          availableCount={availableCount}
          onSeed={handleSeed}
          seeding={seeding}
        />
        <div className="content">
          {page === "dashboard" && <Dashboard needs={needs} volunteers={volunteers} assignments={assignments} setPage={setPage} />}
          {page === "needs" && <NeedsPage />}
          {page === "volunteers" && <VolunteersPage assignments={assignments} />}
          {page === "map" && <MapPage needs={needs} volunteers={volunteers} />}
          {page === "matching" && <MatchingPage needs={needs} onAssign={loadAll} />}
          {page === "submit-need" && <SubmitNeed setPage={setPage} />}
          {page === "add-volunteer" && <AddVolunteer setPage={setPage} />}
        </div>
      </div>
    </div>
  );
}
